import{_ as a}from"./chunks/v2-home.CwZbXCiA.js";import{_ as r,a as e}from"./chunks/v2-wizard-step2.B6X1eXRO.js";import{_ as i,o as l,c as o,ag as s}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"多工作区","description":"","frontmatter":{},"headers":[],"relativePath":"guide/workspace.md","filePath":"guide/workspace.md","lastUpdated":1776674651000}'),d={name:"guide/workspace.md"};function n(p,t,c,h,_,m){return l(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="多工作区" tabindex="-1">多工作区 <a class="header-anchor" href="#多工作区" aria-label="Permalink to &quot;多工作区&quot;">​</a></h1><p>Sync the Spire 支持创建多个工作区，可以为不同的游戏或不同的 Mod 配置创建独立的工作区，互不干扰。</p><h2 id="工作区主页" tabindex="-1">工作区主页 <a class="header-anchor" href="#工作区主页" aria-label="Permalink to &quot;工作区主页&quot;">​</a></h2><p>打开软件后看到的就是工作区主页，以卡片形式展示所有已创建的工作区。</p><p><img src="'+a+'" alt="工作区主页"></p><ul><li>每张卡片显示工作区名称、游戏类型图标和配置状态</li><li>绿色圆点表示已配置完成，灰色表示尚未配置</li><li>上方有搜索框，可按名称快速过滤</li></ul><h2 id="创建工作区" tabindex="-1">创建工作区 <a class="header-anchor" href="#创建工作区" aria-label="Permalink to &quot;创建工作区&quot;">​</a></h2><ol><li><p>点击「<strong>新建工作区</strong>」</p></li><li><p><strong>第一步</strong>：选择游戏类型</p><p><img src="'+r+'" alt="选择游戏类型"></p><p>目前支持的游戏：</p><table tabindex="0"><thead><tr><th>游戏</th><th>状态</th></tr></thead><tbody><tr><td>杀戮尖塔 2</td><td>✅ 完整支持</td></tr><tr><td>星露谷物语</td><td>🚧 即将支持</td></tr><tr><td>Minecraft</td><td>🚧 即将支持</td></tr><tr><td>通用</td><td>✅ 基础 Git 同步</td></tr></tbody></table></li><li><p><strong>第二步</strong>：输入工作区名称，点击「<strong>创建</strong>」</p><p><img src="'+e+'" alt="输入工作区名称"></p></li></ol><p>创建完成后自动进入配置页面。</p><h2 id="标签页管理" tabindex="-1">标签页管理 <a class="header-anchor" href="#标签页管理" aria-label="Permalink to &quot;标签页管理&quot;">​</a></h2><p>打开一个工作区后，它会以标签页的形式显示在顶部栏中。</p><ul><li>点击标签可在不同工作区之间快速切换</li><li>点击标签上的 × 关闭该工作区标签（不会删除工作区）</li><li>最左侧的「主页」标签始终存在，点击返回工作区主页</li></ul><h2 id="管理工作区" tabindex="-1">管理工作区 <a class="header-anchor" href="#管理工作区" aria-label="Permalink to &quot;管理工作区&quot;">​</a></h2><ul><li><strong>重命名</strong>：在仪表盘顶部点击工作区名称即可修改</li><li><strong>删除</strong>：在主页的工作区卡片上点击删除图标，确认后删除</li><li><strong>设置</strong>：点击卡片上的齿轮图标，进入该工作区的配置页面</li></ul><div class="danger custom-block"><p class="custom-block-title">删除不可恢复</p><p>删除工作区会清除该工作区的所有本地数据（仓库、备份等）。请确认不再需要后再操作。</p></div>',15)])])}const k=i(d,[["render",n]]);export{f as __pageData,k as default};
